
document.addEventListener("DOMContentLoaded",function(){console.log(1);const popularItems=document.querySelector('#popular-items__container'),hoverItemClass='popular-item';popularItems.addEventListener('mouseover',mouseOverCardHandler);popularItems.addEventListener('mouseout',mouseOutCardHandler);function mouseOverCardHandler(evt){console.log('mouseEnterCardHandler');const hoveredItem=evt.target.closest('.'+hoverItemClass);if(hoveredItem!==undefined&&hoveredItem!==null){const popularInfoBlock=hoveredItem.querySelector('.popular-info'),popularInfoDetailBlock=hoveredItem.querySelector('.popular-info__detail');popularInfoBlock.classList.add('current');popularInfoDetailBlock.classList.add('current');}}
function mouseOutCardHandler(evt){console.log("mouseLeaveCardHandler");const hoveredItem=evt.target.closest('.'+hoverItemClass);if(hoveredItem!==undefined&&hoveredItem!==null){const popularInfoBlock=hoveredItem.querySelector('.popular-info'),popularInfoDetailBlock=hoveredItem.querySelector('.popular-info__detail');popularInfoBlock.classList.remove('current');popularInfoDetailBlock.classList.remove('current');}}});



document.addEventListener("DOMContentLoaded",function(){const burger=document.querySelector('#burger'),navList=document.querySelector('#nav-list'),overlay=document.querySelector('#overlay'),lastLineBurger=document.querySelector('.line-3');if(issetItem(burger)){burger.addEventListener('click',openAndCloseMenu);}
function openAndCloseMenu(e){if(issetItem(overlay)){overlay.classList.toggle('active');navList.classList.toggle('active');burger.classList.toggle('clicked-js');if(navList.classList.contains('active')){document.body.classList.add('lock');}else{document.body.classList.remove('lock');}
makeCloseButtonFromBurger();}}
function issetItem(item){if(item!==null&&item!==undefined)return true;return false;}
function makeCloseButtonFromBurger(){if(burger.classList.contains('clicked-js')){lastLineBurger.style.display='none';}else{lastLineBurger.style.display='block';}}});

import Swiper from"https://cdn.jsdelivr.net/npm/swiper@10/swiper-bundle.min.mjs";document.addEventListener("DOMContentLoaded",function(){const swiper=new Swiper('.popular-slider',{slidesPerView:2,slidesPerGroup:1,centeredSlides:true,initialSlide:1,breakpoints:{1200:{slidesPerView:3,},768:{slidesPerView:2,spaceBetween:0,},576:{slidesPerView:1,}}});})